// Route CodeRabbit critical alerts to appropriate channels
// Based on CBAMValid regulatory severity mapping
const alert = $input.first().json;

const severityMap = {
  'MISSING_EU_CITATION': { priority: 'P1', channel: ['slack', 'jira', 'email'], message: 'EU regulation citation missing — legal liability risk' },
  'FLOAT_ARITHMETIC': { priority: 'P1', channel: ['slack', 'email'], message: 'Float arithmetic in CBAM calculation — precision non-compliance' },
  'DEFAULT_VALUE_NO_FLAG': { priority: 'P1', channel: ['slack', 'jira', 'email'], message: 'Default value used without is_eu_default_applied flag' },
  'HARDCODED_EMISSION_FACTOR': { priority: 'P2', channel: ['email'], message: 'Hardcoded emission factor outside registry' },
  'AUDIT_TRAIL_VIOLATION': { priority: 'P0', channel: ['slack', 'jira', 'email', 'pagerduty'], message: 'Audit trail immutability violation — legal compliance required' },
  'PRECURSOR_ALLOCATION_ERROR': { priority: 'P0', channel: ['slack', 'jira', 'email', 'pagerduty'], message: 'Mass balance closure violation (>0.01% tolerance)' },
  'CERTIFICATE_HASH_COLLISION': { priority: 'P0', channel: ['slack', 'jira', 'email', 'pagerduty'], message: 'Certificate hash collision — cryptographic integrity breach' },
  'ACADEMIC_OVERSIGHT_MISSING': { priority: 'P1', channel: ['slack', 'email'], message: 'Academic oversight block missing — E-E-A-T authority risk' },
  'SESSION_TTL_FAILURE': { priority: 'P1', channel: ['slack', 'jira', 'email'], message: 'Session TTL enforcement failure — data retention violation' },
};

const ruleType = alert.ruleType || alert.type || 'UNKNOWN';
const mapping = severityMap[ruleType] || { priority: 'P3', channel: ['email'], message: 'Unknown CodeRabbit alert type' };

const result = {
  ...alert,
  mappedPriority: mapping.priority,
  mappedChannels: mapping.channel,
  mappedMessage: mapping.message,
  routedAt: new Date().toISOString(),
  action: mapping.priority === 'P0' ? 'BLOCK_DEPLOYMENT' : 'REQUIRE_REVIEW',
};

console.log(`[W23] CodeRabbit alert: ${ruleType} → ${mapping.priority} → ${mapping.channel.join(',')}`);

return [{ json: result }];

